schema:
={
  "type": "OBJECT",
  "properties": {
    "service_context": {
      "type": "OBJECT",
      "description": "Service Context (SVC) node to be injected dynamically into downstream prompts. Must be deterministic and grounded in the provided input (no hallucinated facts).",
      "properties": {
        "SVC_PROVIDER_IDENTITY": {
          "type": "STRING",
          "description": "Provider identity: name/category/positioning/differentials. Format as bullet list using '- '. Use [MISSING] if no evidence."
        },
        "SVC_OFFERINGS_BY_VERTICAL": {
          "type": "STRING",
          "description": "Offerings grouped by vertical. Bullet list grouped by headings if available. Use [MISSING] if no evidence."
        },
        "SVC_PERSONA_TARGETING": {
          "type": "STRING",
          "description": "Persona targeting matrix with Best/Good/Fair/Avoid in a fixed, repeatable format. Use mapped roles when only areas are cited. Use [MISSING] if no evidence."
        },
        "SVC_KEYWORDS": {
          "type": "STRING",
          "description": "Keywords extracted from input (products, pains, acronyms). Bullet list using '- '. Use [MISSING] if no evidence."
        },
        "SVC_CORE_PROBLEM_FOCUS": {
          "type": "STRING",
          "description": "Core problems: 3-10 pains/frictions. Bullet list using '- '. Use [MISSING] if no evidence."
        },
        "SVC_CORE_SOLUTIONS": {
          "type": "STRING",
          "description": "Core solutions: 3-12 solutions/capabilities/products explicitly present in input. Bullet list using '- '. Use [MISSING] if no evidence."
        },
        "SVC_UVP_ARSENAL": {
          "type": "STRING",
          "description": "UVP Arsenal by persona. Each persona block should be stable and repeatable, using only input evidence. Use [MISSING] if no evidence; use [MISSING: uvpArsenal.<field>] within blocks when partial."
        },
        "SVC_CASE_LIBRARY": {
          "type": "STRING",
          "description": "Case Library. Each case should appear in input order. Use [MISSING] if no evidence; use [MISSING: caseLibrary.<field>] within cases when partial."
        },
        "SVC_RESEARCH_FOCUS_AREAS": {
          "type": "STRING",
          "description": "Research focus areas: signals/context to prioritize. Bullet list using '- '. Use [MISSING] if no evidence."
        },
        "SVC_STRATEGIC_LENS": {
          "type": "STRING",
          "description": "Strategic lens: priorities/tradeoffs. Bullet list using '- ' (e.g., 'priorize evidências de X', 'ignore Y'). Use [MISSING] if no evidence."
        },
        "SVC_CASE_MATCH_DRIVERS": {
          "type": "STRING",
          "description": "Allowed drivers for case matching (no legacy GTM residue). Bullet list using '- '. Use [MISSING] if no evidence."
        },

        "meta": {
          "type": "OBJECT",
          "description": "Optional metadata for QA and determinism. Does not contain business content.",
          "properties": {
            "vertical_id": {
              "type": "STRING",
              "nullable": true,
              "description": "Optional vertical identifier, if provided in the input."
            },
            "missing_policy": {
              "type": "STRING",
              "description": "Policy for missing values. Must be exactly: '[MISSING]' for whole-slot absence and '[MISSING: <subfield>]' for partial absence."
            },
            "determinism_notes": {
              "type": "STRING",
              "nullable": true,
              "description": "Short note confirming stable ordering and no invented facts. Keep concise."
            }
          },
          "required": ["vertical_id", "missing_policy", "determinism_notes"]
        }
      },
      "required": [
        "SVC_PROVIDER_IDENTITY",
        "SVC_OFFERINGS_BY_VERTICAL",
        "SVC_PERSONA_TARGETING",
        "SVC_KEYWORDS",
        "SVC_CORE_PROBLEM_FOCUS",
        "SVC_CORE_SOLUTIONS",
        "SVC_UVP_ARSENAL",
        "SVC_CASE_LIBRARY",
        "SVC_RESEARCH_FOCUS_AREAS",
        "SVC_STRATEGIC_LENS",
        "SVC_CASE_MATCH_DRIVERS",
        "meta"
      ]
    }
  },
  "required": ["service_context"]
}

={
  "type": "OBJECT",
  "properties": {
    "domain": { "type": "STRING", "description": "Input domain normalized (no protocol/path)." },
    "name": { "type": "STRING", "nullable": true, "description": "Company name (common or legal)." },
    "linkedin_url": { "type": "STRING", "nullable": true, "description": "Canonical LinkedIn company page URL (validated against domain/branding)." },
    "description": { "type": "STRING", "nullable": true, "description": "One-sentence description (max ~300 chars)." },
    "primary_industry": { "type": "STRING", "nullable": true, "description": "Single best-fit industry label." },

    "size": {
      "type": "STRING",
      "nullable": true,
      "enum": ["1-10","11-50","51-200","201-500","501-1000","1001-5000","5001-10000","10000+"],
      "description": "Employee headcount range (allowed bins)."
    },

    "type": {
      "type": "STRING",
      "enum": ["Private","Public","Subsidiary","Nonprofit","Government","Partnership","Self-employed","Unknown"],
      "description": "Organization type (allowed values)."
    },

    "location": { "type": "STRING", "nullable": true, "description": "HQ location as City, State/Region when possible." },
    "country": { "type": "STRING", "nullable": true, "description": "HQ country name (e.g., Brazil, United States)." },
    "notes": { "type": "STRING", "nullable": true, "description": "Brief justification + sources checked + why any nulls." }
  },
  "required": ["domain","name","linkedin_url","description","primary_industry","size","type","location","country","notes"]
}

={
  "type": "OBJECT",
  "properties": {
    "executive_summary": {
      "type": "STRING",
      "description": "Concise executive summary of the person and why they matter for the goal (max ~1200 chars)."
    },
    "professional_profile": {
      "type": "OBJECT",
      "properties": {
        "career_timeline": {
          "type": "STRING",
          "description": "High-signal career timeline in plain text (roles, companies, years)."
        },
        "achievements": {
          "type": "STRING",
          "description": "Notable achievements, impact metrics, awards, and standout outcomes."
        },
        "skills_expertise_focus": {
          "type": "STRING",
          "description": "Core expertise, functional focus, domain knowledge, and areas of strength."
        }
      },
      "required": ["career_timeline", "achievements", "skills_expertise_focus"]
    },
    "company_deep_dive": {
      "type": "OBJECT",
      "properties": {
        "stated_goals_and_challenges": {
          "type": "STRING",
          "description": "Company goals/challenges as stated publicly by the person/company, plus inferred constraints."
        },
        "recent_developments": {
          "type": "STRING",
          "description": "Recent events that changed priorities (launches, funding, hiring, partnerships, pivots, layoffs)."
        },
        "gtm_landscape": {
          "type": "STRING",
          "description": "GTM context: customers, channels, positioning, competitors, ecosystem partners."
        }
      },
      "required": ["stated_goals_and_challenges", "recent_developments", "gtm_landscape"]
    },
    "industry_engagement_and_influence": {
      "type": "OBJECT",
      "properties": {
        "thought_leadership": {
          "type": "STRING",
          "description": "Topics they publish/speak about, consistent narratives, and POV themes."
        },
        "professional_network_analysis": {
          "type": "STRING",
          "description": "Signals from network: key connections, communities, partnerships, and influence radius."
        },
        "media_appearances": {
          "type": "STRING",
          "description": "Podcasts, interviews, panels, quoted articles, conference appearances."
        }
      },
      "required": ["thought_leadership", "professional_network_analysis", "media_appearances"]
    },
    "personal_dimensions": {
      "type": "OBJECT",
      "properties": {
        "interests_and_motivations": {
          "type": "STRING",
          "description": "Personal interests, motivations, and values (only if publicly available)."
        },
        "community_involvement": {
          "type": "STRING",
          "description": "Boards, charities, open source, mentoring, local initiatives, affiliations."
        },
        "communication_style": {
          "type": "STRING",
          "description": "Communication patterns: tone, formality, preferred channels, pacing, openness."
        }
      },
      "required": ["interests_and_motivations", "community_involvement", "communication_style"]
    },
    "strategic_analysis": {
      "type": "OBJECT",
      "properties": {
        "relevance_to_tam_acceleration": {
          "type": "STRING",
          "description": "Why this person matters for TAM acceleration: leverage, buying power, influence, timing."
        },
        "engagement_angles": {
          "type": "STRING",
          "description": "Best angles to engage: value hooks, relevant problems, timely triggers, mutual context."
        },
        "conversation_starters": {
          "type": "STRING",
          "description": "Specific openers/questions grounded in evidence (avoid generic lines)."
        }
      },
      "required": ["relevance_to_tam_acceleration", "engagement_angles", "conversation_starters"]
    },
    "additional_findings": {
      "type": "STRING",
      "nullable": true,
      "description": "Anything relevant that does not fit other fields; include uncertainty notes."
    },
    "potential_future_trajectories": {
      "type": "STRING",
      "nullable": true,
      "description": "Likely next steps for the person/company based on signals; label as inference when applicable."
    },
    "notes": {
      "type": "STRING",
      "nullable": true,
      "description": "Sources checked + brief justification + why any nulls/unknowns."
    }
  },
  "required": [
    "executive_summary",
    "professional_profile",
    "company_deep_dive",
    "industry_engagement_and_influence",
    "personal_dimensions",
    "strategic_analysis",
    "additional_findings",
    "potential_future_trajectories",
    "notes"
  ]
}

={
  "type": "OBJECT",
  "properties": {
    "prospectIdentifier": {
      "type": "OBJECT",
      "description": "Core identifiers for the prospect (do not include PII beyond name/title/company).",
      "properties": {
        "fullName": {
          "type": "STRING",
          "description": "Lead full name as provided in the input dossier."
        },
        "title": {
          "type": "STRING",
          "description": "Current job title as provided in the input dossier."
        },
        "companyName": {
          "type": "STRING",
          "description": "Company name as provided in the input dossier."
        }
      },
      "required": ["fullName", "title", "companyName"]
    },
    "strategicInsights": {
      "type": "ARRAY",
      "description": "Top 1-2 prioritized pain points and internal opportunities, framed from the prospect's POV and mapped to TAM Acceleration relevance.",
      "minItems": 1,
      "maxItems": 2,
      "items": {
        "type": "OBJECT",
        "properties": {
          "identifiedPainPoint": {
            "type": "OBJECT",
            "description": "The inferred professional pain point from the prospect's perspective, aligned to TAM Acceleration's GTM problems.",
            "properties": {
              "title": {
                "type": "STRING",
                "description": "Clear, specific pain point title from the individual's POV."
              },
              "description": {
                "type": "STRING",
                "description": "Pain point description from the individual's POV. Must be specific and reflect GTM pressure (pipeline, CAC, churn, budget waste, inefficiency)."
              }
            },
            "required": ["title", "description"]
          },
          "identifiedOpportunity": {
            "type": "OBJECT",
            "description": "The internal initiative the prospect could champion to solve the pain and advance their career, enabled by TAM Acceleration outcomes.",
            "properties": {
              "title": {
                "type": "STRING",
                "description": "Clear, specific opportunity title from the individual's POV."
              },
              "description": {
                "type": "STRING",
                "description": "Opportunity description framed as an internal outcome/initiative, not as 'buy our service'. Must connect to predictable pipeline, evergreen inbound, or RevOps optimization."
              }
            },
            "required": ["title", "description"]
          },
          "reasoning": {
            "type": "STRING",
            "description": "Step-by-step justification connecting dossier evidence to the pain point and opportunity, and explicitly mapping to TAM Acceleration's core offerings."
          },
          "confidenceLevel": {
            "type": "STRING",
            "enum": ["High", "Medium", "Low"],
            "description": "Confidence level in the inference based on strength of evidence."
          },
          "confidenceReasoning": {
            "type": "STRING",
            "description": "Brief explanation of why the confidence level was assigned (mention which evidence is strong/weak)."
          }
        },
        "required": [
          "identifiedPainPoint",
          "identifiedOpportunity",
          "reasoning",
          "confidenceLevel",
          "confidenceReasoning"
        ]
      }
    }
  },
  "required": ["prospectIdentifier", "strategicInsights"]
}

={
  "type": "OBJECT",
  "properties": {
    "prospectIdentifier": {
      "type": "OBJECT",
      "description": "Core identifiers for the prospect (do not include PII beyond name/title/company).",
      "properties": {
        "fullName": {
          "type": "STRING",
          "description": "Lead full name as provided in the input dossier."
        },
        "title": {
          "type": "STRING",
          "description": "Current job title as provided in the input dossier."
        },
        "companyName": {
          "type": "STRING",
          "description": "Company name as provided in the input dossier."
        }
      },
      "required": ["fullName", "title", "companyName"]
    },
    "bestMatchedUVP": {
      "type": "OBJECT",
      "description": "The best-matched value proposition for this prospect, plus how to position the conversation.",
      "properties": {
        "selectedUVP": {
          "type": "STRING",
          "description": "The selected UVP statement that best fits the prospect's context."
        },
        "associatedSolution": {
          "type": "STRING",
          "description": "The solution/offer mapped to the selected UVP."
        },
        "conversationAngle": {
          "type": "STRING",
          "description": "Recommended conversation angle (hook) tailored to the prospect."
        }
      },
      "required": ["selectedUVP", "associatedSolution", "conversationAngle"]
    },
    "analysis": {
      "type": "OBJECT",
      "description": "Supporting rationale and traceability of how the result was derived.",
      "properties": {
        "reasoning": {
          "type": "STRING",
          "description": "Step-by-step justification linking input evidence to the chosen UVP, solution, and conversation angle."
        },
        "stepsTaken": {
          "type": "ARRAY",
          "description": "High-level steps performed during analysis (bullet-like).",
          "minItems": 1,
          "items": {
            "type": "STRING"
          }
        }
      },
      "required": ["reasoning", "stepsTaken"]
    }
  },
  "required": ["prospectIdentifier", "bestMatchedUVP", "analysis"]
}

={
  "type": "OBJECT",
  "properties": {
    "matchedCaseStudy": {
      "type": "OBJECT",
      "description": "The case study that best matches the current prospect/context.",
      "properties": {
        "clientName": {
          "type": "STRING",
          "description": "Client name from the matched case study."
        },
        "simpleExplanation": {
          "type": "STRING",
          "description": "Short explanation of why this case study matches (1-2 sentences)."
        },
        "fullExplanation": {
          "type": "OBJECT",
          "description": "Full structured explanation of the match using consistent narrative fields.",
          "properties": {
            "industry": {
              "type": "STRING",
              "description": "Industry context of the matched case study."
            },
            "painPoint": {
              "type": "STRING",
              "description": "Primary pain point addressed in the case study that maps to the prospect's situation."
            },
            "solution": {
              "type": "STRING",
              "description": "Solution implemented in the case study that relates to the prospect's needs."
            },
            "impact": {
              "type": "STRING",
              "description": "Outcome/impact achieved in the case study (metrics preferred when available)."
            }
          },
          "required": ["industry", "painPoint", "solution", "impact"]
        }
      },
      "required": ["clientName", "simpleExplanation", "fullExplanation"]
    },
    "reasoningForMatch": {
      "type": "STRING",
      "description": "Step-by-step reasoning explaining why this case study is the best match given the input evidence."
    }
  },
  "required": ["matchedCaseStudy", "reasoningForMatch"]
}
